function solve(nums: number[]): number {
    const n = nums.length;
    const sorted = [...nums].sort((a, b) => a - b);

    // For each possible k, check if it's possible to sort the array using swaps with AND equal to k
    for (let k = n - 1; k >= 0; k--) {
        const visited = new Set<number>();
        let canSort = true;

        for (let i = 0; i < n; i++) {
            if (visited.has(i)) continue;

            // Find a j such that nums[i] & nums[j] == k and j is not visited
            let found = false;
            for (let j = 0; j < n; j++) {
                if (i === j || visited.has(j)) continue;
                if ((nums[i] & nums[j]) === k) {
                    visited.add(i);
                    visited.add(j);
                    found = true;
                    break;
                }
            }

            if (!found) {
                canSort = false;
                break;
            }
        }

        if (canSort) {
            return k;
        }
    }

    return 0;
}

